describe("Temporal.PlainDate",()=>{describe("creation and parsing",()=>{it("can be created from an RFC 9557 string",()=>{let e=Temporal.PlainDate.from("2021-08-19");expect(e.toString()).toContain("2021-08-19")}),it("can be created from an own object",()=>{let e=Temporal.PlainDate.from("2021-08-19"),o=Temporal.PlainDate.from(e);expect(e).toEqual(o)}),it("can be created from an object containing properties",()=>{let e=Temporal.PlainDate.from({year:2006,month:8,day:24});expect(e.toString()).toEqual("2006-08-24")})}),describe("arithmetic methods",()=>{let e=Temporal.PlainDate.from("2020-01-01"),o=Temporal.PlainDate.from("2020-01-02");it("add() advances the date",()=>{let t=e.add({days:1});expect(t.day).toBe(2)}),it("compare() method works for two PlainDate objects",()=>{expect(Temporal.PlainDate.compare(e,o)).toBe(-1),expect(Temporal.PlainDate.compare(o,e)).toBe(1),expect(Temporal.PlainDate.compare(e,e)).toBe(0)}),it("equals() verifies if two PlainDate are equal",()=>{let t=Temporal.PlainDate.from("2020-01-01");expect(e.equals(t)).toBe(!0)}),it("since() returns correct duration",()=>{let t=o.since(e);expect(t.sign).toBe(1),expect(t.years).toBe(0),expect(t.months).toBe(0),expect(t.days).toBe(1)}),it("subtract() decrements by a duration",()=>{let t=o.subtract({days:1});expect(t.day).toBeLessThan(o.day)}),it("toPlainDateTime() returns a Temporal.PlainDateTime",()=>{let t=e.toPlainDateTime();expect(t).toBeInstanceOf(Temporal.PlainDateTime),expect(t.toString()).toBe("2020-01-01T00:00:00");let a=e.toPlainDateTime("12:34:56");expect(a.toString()).toBe("2020-01-01T12:34:56");let n=Temporal.PlainTime.from("12:34:56"),i=e.toPlainDateTime(n);expect(i.toString()).toBe("2020-01-01T12:34:56")}),it("toZonedDateTime() returns a Temporal.ZonedDateTime",()=>{let t=e.toZonedDateTime("Asia/Tokyo");expect(t).toBeInstanceOf(Temporal.ZonedDateTime),expect(t.toString()).toBe("2020-01-01T00:00:00+09:00[Asia/Tokyo]");let a=e.toZonedDateTime({timeZone:"Asia/Tokyo"});expect(a.toString()).toBe("2020-01-01T00:00:00+09:00[Asia/Tokyo]");let n=e.toZonedDateTime({timeZone:"Asia/Tokyo",plainTime:"12:34:56"});expect(n.toString()).toBe("2020-01-01T12:34:56+09:00[Asia/Tokyo]");let i=Temporal.PlainTime.from("12:34:56"),r=e.toZonedDateTime({timeZone:"Asia/Tokyo",plainTime:i});expect(r.toString()).toBe("2020-01-01T12:34:56+09:00[Asia/Tokyo]")}),it("toString() returns an ISO string representation",()=>{let t=e.toString();expect(typeof t).toBe("string"),expect(t).toBe("2020-01-01")}),it("until() returns correct duration",()=>{let t=e.until(o);expect(t.sign).toBe(1),expect(t.years).toBe(0),expect(t.months).toBe(0),expect(t.days).toBe(1)}),it("valueOf() throws a TypeError",()=>{expect(()=>{+e}).toThrow()}),it("with() method returns a new PlainDate with updated fields",()=>{let t=e.with({day:15});expect(t.day).toBe(15),expect(t.month).toBe(e.month)})}),describe("properties",()=>{let e=Temporal.PlainDate.from("2020-01-01");it("should have correct date and time properties",()=>{expect(e.year).toBe(2020),expect(e.month).toBe(1),expect(e.day).toBe(1),expect(e.dayOfYear).toBe(1),expect(e.daysInMonth).toBe(31),expect(e.daysInYear).toBe(366),expect(e.inLeapYear).toBe(!0)}),it("has correct toStringTag",()=>{expect(Object.prototype.toString.call(e)).toBe("[object Temporal.PlainDate]")})})});
